"use strict";(globalThis.webpackChunkdrpd_docs=globalThis.webpackChunkdrpd_docs||[]).push([[613],{6595(e,t,o){o.r(t),o.d(t,{assets:()=>c,contentTitle:()=>s,default:()=>d,frontMatter:()=>a,metadata:()=>n,toc:()=>h});const n=JSON.parse('{"id":"how-to/protection-mechanisms","title":"Using Dr. PD\'s protection mechanisms","description":"The USB-PD protocol includes a set of safety mechanisms that are designed to protect both the source and sink devices from damage in case of abnormal conditions, such as overvoltage, overcurrent, or short circuits. These have their limitations, but are normally \u201cgood enough\u201d for most applications.","source":"@site/docs/how-to/protection-mechanisms.mdx","sourceDirName":"how-to","slug":"/how-to/protection-mechanisms","permalink":"/drpd/docs/how-to/protection-mechanisms","draft":false,"unlisted":false,"editUrl":"https://github.com/T76-org/drpd/tree/main/docs/docs/how-to/protection-mechanisms.mdx","tags":[],"version":"current","frontMatter":{},"sidebar":"tutorialSidebar","previous":{"title":"Capturing USB-PD messages","permalink":"/drpd/docs/how-to/capturing-messages"},"next":{"title":"Using triggers and the sync output","permalink":"/drpd/docs/how-to/using-triggers"}}');var r=o(4848),i=o(8453);const a={},s="Using Dr. PD's protection mechanisms",c={},h=[{value:"Overvoltage and overcurrent protection",id:"overvoltage-and-overcurrent-protection",level:2},{value:"Port 2 lock-out",id:"port-2-lock-out",level:2},{value:"Reverse polarity protection",id:"reverse-polarity-protection",level:2}];function l(e){const t={admonition:"admonition",em:"em",h1:"h1",h2:"h2",header:"header",li:"li",p:"p",ul:"ul",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(t.header,{children:(0,r.jsx)(t.h1,{id:"using-dr-pds-protection-mechanisms",children:"Using Dr. PD's protection mechanisms"})}),"\n",(0,r.jsx)(t.p,{children:"The USB-PD protocol includes a set of safety mechanisms that are designed to protect both the source and sink devices from damage in case of abnormal conditions, such as overvoltage, overcurrent, or short circuits. These have their limitations, but are normally \u201cgood enough\u201d for most applications."}),"\n",(0,r.jsx)(t.p,{children:"Dr. PD is designed to let you explore and test USB-PD devices in ways that are not always compatible with these protection mechanisms, and so it implements its own set of protections that are designed to work in tandem with their native counterparts, and to allow you to safely test and characterize USB-PD devices without risking damage to Dr. PD itself or to the devices you are testing."}),"\n",(0,r.jsxs)(t.admonition,{type:"danger",children:[(0,r.jsx)(t.p,{children:"While Dr. PD's protection mechanisms are designed to prevent damage to Dr. PD and to the devices you are testing, they are not foolproof, and there is always a risk of damage when testing USB-PD devices, especially if you are testing at high power levels or with devices that have unknown or poorly implemented protection mechanisms."}),(0,r.jsx)(t.p,{children:"Therefore, it's important to always take appropriate safety precautions when testing USB-PD devices with Dr. PD, such as using high-quality cables and connectors, making sure that your devices are on a non-flammable surface, and keeping a fire extinguisher nearby just in case. We also recommend not leaving Dr. PD unattended while testing, especially when testing at high power levels or with devices that have unknown or poorly implemented protection mechanisms."})]}),"\n",(0,r.jsx)(t.h2,{id:"overvoltage-and-overcurrent-protection",children:"Overvoltage and overcurrent protection"}),"\n",(0,r.jsx)(t.p,{children:"Dr. PD implements its own set of configurable overvoltage and overcurrent protections. These protections are designed to exhibit a very specific set of behaviours:"}),"\n",(0,r.jsxs)(t.ul,{children:["\n",(0,r.jsx)(t.li,{children:"They act as on/off switches that cut the power delivery between ports 1 and 2 and between port 1 and the banana connectors when triggered. Dr. PD does not implement any kind of current limiting or voltage clamping behavior, and instead relies on cutting the power delivery to protect itself and the devices you are testing."}),"\n",(0,r.jsx)(t.li,{children:"They are implemented in firmware; while this means that they remain active even when Dr. PD is not connected to a host device, it also means that there is a small delay between the moment when the overage condition occurs and when the protection mechanism is triggered\u2014typically on the order of 100\xb5s."}),"\n",(0,r.jsx)(t.li,{children:"They have no built-in tolerance, and will trigger as soon as the voltage or current exceeds the configured threshold."}),"\n",(0,r.jsx)(t.li,{children:"They are bidirectional, and will cut the power delivery in both directions between ports 1 and 2 and between port 1 and the banana connectors when triggered. This means that if you have a device connected to port 2 or to the banana connectors while testing a source device on port 1, they will also be protected by the overvoltage and overcurrent protections of Dr. PD."}),"\n",(0,r.jsxs)(t.li,{children:["Once triggered, they will ",(0,r.jsx)(t.em,{children:"never"})," reset automatically, and will require a manual reset by the user in order to resume normal operation. This is to prevent any kind of \u201cauto-retry\u201d behaviour that could potentially cause damage to Dr. PD or to the devices you are testing."]}),"\n"]}),"\n",(0,r.jsx)(t.p,{children:"You can configure the overvoltage and overcurrent protection thresholds in the control app by selecting Protection -> Set thresholds\u2026 from the menu. The thresholds are set in terms of voltage and current levels, and you can set them to any values that are appropriate for your tests, as long as they are within the limits of Dr. PD's hardware (60V and 6A)."}),"\n",(0,r.jsx)(t.p,{children:"When a protection mechanism is triggered, the OVP or OCP indicator in the control app's header will flash red until you reset it. You can reset the protection mechanism by selecting Protection -> Reset from the menu."}),"\n",(0,r.jsx)(t.admonition,{type:"info",children:(0,r.jsx)(t.p,{children:"The OVP/OCP thresholds that you set in the control app are stored in non-volatile memory on Dr. PD, and will persist across power cycles. This means that if you set a threshold and then power cycle Dr. PD, the threshold will still be in effect when you power it back on. This can be useful for ensuring that your tests are always protected by the same thresholds, even if you forget to set them before each test, but it also means that you should be careful when setting the thresholds, and make sure to set them to appropriate values for your tests in order to avoid accidentally triggering the protection mechanisms and having to reset them before you can resume testing."})}),"\n",(0,r.jsx)(t.h2,{id:"port-2-lock-out",children:"Port 2 lock-out"}),"\n",(0,r.jsx)(t.p,{children:"In addition to the overvoltage and overcurrent protections, Dr. PD also implements a port 2 lock-out mechanism that is designed to protect any device that you might have inadvertently left connected to port 2 while testing a source device on port 1 in Sink mode."}),"\n",(0,r.jsx)(t.p,{children:"When the port 2 lock-out is enabled, Dr. PD will disconnect the USB-PD bus and the VBUS line from port 2, effectively preventing any power delivery or communication between port 1 and port 2. This means that if you have a device connected to port 2 while testing a source device on port 1, it will be protected from any potential damage that could occur if the source device were to malfunction or if you were to accidentally set inappropriate overvoltage or overcurrent thresholds."}),"\n",(0,r.jsx)(t.h2,{id:"reverse-polarity-protection",children:"Reverse polarity protection"}),"\n",(0,r.jsx)(t.p,{children:"The banana connectors also feature a reverse polarity protection mechanism that is designed to prevent damage to Dr. PD and to the devices you are testing in case you accidentally connect the positive and negative of an external power source or load in reverse while testing a source device on port 1."}),"\n",(0,r.jsx)(t.p,{children:"When the reverse polarity protection is triggered, Dr. PD will disconnect the VBUS line from the banana connectors, effectively preventing any power delivery between both ports and the banana connectors. There is no indication in the control app when the reverse polarity protection is triggered, but you will notice that the VBUS voltage on the banana connectors will drop to 0V, and that any devices connected to the banana connectors will stop receiving power."})]})}function d(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,r.jsx)(t,{...e,children:(0,r.jsx)(l,{...e})}):l(e)}},8453(e,t,o){o.d(t,{R:()=>a,x:()=>s});var n=o(6540);const r={},i=n.createContext(r);function a(e){const t=n.useContext(i);return n.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function s(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(r):e.components||r:a(e.components),n.createElement(i.Provider,{value:t},e.children)}}}]);